// Parse Claude API response and merge with existing lead data
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Get the Claude API response
    const apiResponse = item.json;

    // Extract the AI-generated content from Claude's response structure
    let enrichmentData = {};

    if (apiResponse.content && Array.isArray(apiResponse.content)) {
      // Claude returns content in an array with text blocks
      const textContent = apiResponse.content.find(block => block.type === 'text');

      if (textContent && textContent.text) {
        // Parse the JSON from the text content
        try {
          // Extract JSON from the text (it might be wrapped in markdown code blocks)
          let jsonText = textContent.text;

          // Remove markdown code blocks if present
          jsonText = jsonText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

          enrichmentData = JSON.parse(jsonText);
        } catch (parseError) {
          console.log('Failed to parse AI response as JSON:', parseError.message);
          enrichmentData = {
            companySize: 'Unknown',
            industry: 'Unknown',
            products: 'Unable to parse',
            targetMarket: 'Unknown',
            techStack: 'Unknown'
          };
        }
      }
    }

    // Merge enrichment data with existing lead data
    const mergedData = {
      domain: item.json.domain || '',
      emails: item.json.emails || [],
      emailCount: item.json.emailCount || 0,
      decisionMakerEmails: item.json.decisionMakerEmails || [],
      decisionMakerCount: item.json.decisionMakerCount || 0,
      categorizedEmails: item.json.categorizedEmails || {},
      contactPages: item.json.contactPages || [],
      contactPageCount: item.json.contactPageCount || 0,
      // AI enrichment data
      companySize: enrichmentData.companySize || 'Unknown',
      industry: enrichmentData.industry || 'Unknown',
      products: enrichmentData.products || 'Unknown',
      targetMarket: enrichmentData.targetMarket || 'Unknown',
      techStack: enrichmentData.techStack || 'Unknown',
      // Status
      status: 'enriched'
    };

    results.push({ json: mergedData });

  } catch (error) {
    console.log('Error processing item:', error.message);

    // Return item with error status
    results.push({
      json: {
        domain: item.json.domain || 'Unknown',
        emails: item.json.emails || [],
        emailCount: item.json.emailCount || 0,
        companySize: 'Unknown',
        industry: 'Unknown',
        products: 'Error',
        targetMarket: 'Unknown',
        techStack: 'Unknown',
        status: 'enrichment_failed',
        error: error.message
      }
    });
  }
}

return results;
